VALUES
  ('disabled-7c4986e7-moex-00076', 'disabled-7c4986e7', 'disabled-7c4986e7-moex-113-e0b1f2ed', 'sub-disabled-7c4986e7-04', NULL, 'single_choice', '甲公司 X3 年 12 月 31 日調整前應收帳款餘額為$480,000，備抵壞帳貸餘 $24,000，應收帳款的帳齡分析如下： 帳 齡 金 額 可能收回機率 15天以內 $250,000 0.95 16～30天 80,000 0.92 31～45天 65,000 0.85 46～60天 33,000 0.78 61～90天 22,000 0.48 超過90天 ？ 0.00 甲公司採用帳齡分析法提列壞帳，X3年應提列壞帳費用之金額為：', '["$23,350", "$41,350", "$47,350", "$53,350 30650"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:58+00:00", "source_pdf_sha1": "96d5295faf56", "answer_pdf_sha1": "2f6eb3654efb", "source_family": "moex-gov-tw", "moex": {"exam_code": "113040", "c": "306", "s": "1102", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學", "year": "113", "exam_name": "113年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 15, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "金融保險"}'::jsonb, NULL),
  ('disabled-7c4986e7-moex-00077', 'disabled-7c4986e7', 'disabled-7c4986e7-moex-113-e0b1f2ed', 'sub-disabled-7c4986e7-04', NULL, 'single_choice', '丙公司的倉庫於X9年7月1日發生火災，除FOB起運點交貨之在途進貨 外，倉庫內剩餘存貨的估計殘值$9,500。該批在途進貨購價$58,000，運費 $1,500已經入帳。丙公司存貨相關資料如下：X9年1月1日存貨$62,500 ，X9年1月1日至7月1日間的進貨$403,500，進貨運費$2,500，進貨退 回及折讓$6,000。X9年1月1日至7月1日間的現金銷貨$222,000，賒銷 $250,000，銷貨退回$12,000，銷貨運費$4,500，平均毛利率為銷貨淨額之 25%。以毛利法計算丙公司火災的損失金額為：', '["$46,000", "$48,500", "$50,000", "$58,000"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:58+00:00", "source_pdf_sha1": "96d5295faf56", "answer_pdf_sha1": "2f6eb3654efb", "source_family": "moex-gov-tw", "moex": {"exam_code": "113040", "c": "306", "s": "1102", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學", "year": "113", "exam_name": "113年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 16, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "金融保險"}'::jsonb, NULL),
  ('disabled-7c4986e7-moex-00078', 'disabled-7c4986e7', 'disabled-7c4986e7-moex-113-e0b1f2ed', 'sub-disabled-7c4986e7-04', NULL, 'single_choice', '甲公司存貨使用定期盤存制度，X1年9月份的期初存貨共2,000單位，單 位成本$18，X1年9月份進貨與銷貨資料如下： 9月05日 進貨350單位，每單位成本$22 9月10日 銷貨450單位，每單位售價$38 9月13日 銷貨400單位，每單位售價$40 9月25日 進貨500單位，每單位成本$21 甲公司以成本與淨變現價值孰低法來評價存貨，每單位存貨於 X1 年 9 月 底的淨變現價值$20。在期末一次加權平均法下，甲公司X1年9月底之存 貨金額為：', '["$38,040", "$40,000", "$40,667", "$42,820"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:58+00:00", "source_pdf_sha1": "96d5295faf56", "answer_pdf_sha1": "2f6eb3654efb", "source_family": "moex-gov-tw", "moex": {"exam_code": "113040", "c": "306", "s": "1102", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學", "year": "113", "exam_name": "113年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 17, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "金融保險"}'::jsonb, NULL),
  ('disabled-7c4986e7-moex-00079', 'disabled-7c4986e7', 'disabled-7c4986e7-moex-113-e0b1f2ed', 'sub-disabled-7c4986e7-04', NULL, 'single_choice', '舒結公司 X3 年 1 月 1 日備抵損失貸方餘額$95,200，X3 年舒結公司沖銷 了$68,544 的應收帳款，同時也收回了原先已打消壞帳的應收帳款$19,992 ，X3年的預期信用減損損失為$67,592，X3年12月31日公司合理估計應 收帳款餘額的 6%可能無法收回。舒結公司 X3 年 12 月 31 日應收帳款的 餘額為：', '["$1,186,300", "$1,126,533", "$1,570,800", "$1,904,000"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:58+00:00", "source_pdf_sha1": "96d5295faf56", "answer_pdf_sha1": "2f6eb3654efb", "source_family": "moex-gov-tw", "moex": {"exam_code": "113040", "c": "306", "s": "1102", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學", "year": "113", "exam_name": "113年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 18, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "金融保險"}'::jsonb, NULL),
  ('disabled-7c4986e7-moex-00080', 'disabled-7c4986e7', 'disabled-7c4986e7-moex-113-e0b1f2ed', 'sub-disabled-7c4986e7-04', NULL, 'single_choice', '北平公司於X1 年12月31 日買入南山公司3 年期公司債，面額$500,000 ，票面利率 3%，每年 12 月 31 日付息 1 次。當日該公司債的公允價值為 $498,000，12 個月預期信用損失估計金額為$5,000，北平公司另外支付交 易成本$8,000。若北平公司將該公司債做為按攤銷後成本衡量之投資，則 其X1年12月31日之總帳面金額及攤銷後成本分別為：', '["$506,000、$501,000", "$500,000、$508,000", "$498,000、$506,000", "$498,000、$501,000 30650"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:58+00:00", "source_pdf_sha1": "96d5295faf56", "answer_pdf_sha1": "2f6eb3654efb", "source_family": "moex-gov-tw", "moex": {"exam_code": "113040", "c": "306", "s": "1102", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學", "year": "113", "exam_name": "113年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 19, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "金融保險"}'::jsonb, NULL),
  ('disabled-7c4986e7-moex-00081', 'disabled-7c4986e7', 'disabled-7c4986e7-moex-113-e0b1f2ed', 'sub-disabled-7c4986e7-04', NULL, 'single_choice', '陽光科技公司於 X6 年 1 月 1 日購買 1 項專利權，支付$200,000 作為購買 價格。此外，該公司還支付$25,000 的律師費用以完成購買過程，並支出 $10,000 用於專利權的初步市場研究。該專利權的預計使用壽命為 10 年。 依據國際會計準則第38號「無形資產」，陽光科技公司專利權的成本為：', '["$200,000", "$225,000", "$235,000", "$245,000"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:58+00:00", "source_pdf_sha1": "96d5295faf56", "answer_pdf_sha1": "2f6eb3654efb", "source_family": "moex-gov-tw", "moex": {"exam_code": "113040", "c": "306", "s": "1102", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學", "year": "113", "exam_name": "113年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 20, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "金融保險"}'::jsonb, NULL),
  ('disabled-7c4986e7-moex-00082', 'disabled-7c4986e7', 'disabled-7c4986e7-moex-113-e0b1f2ed', 'sub-disabled-7c4986e7-04', NULL, 'single_choice', '光光公司於 X1 年 7 月 1 日以 99 之價格加計應計利息發行 5 年期的公司 債以籌措資金，面額$1,000,000、票面利率10%，每年4月1日與10月1 日付息。發行債券時，光光公司收到的現金為：', '["$1,015,000", "$1,000,000", "$980,000", "$965,000"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:58+00:00", "source_pdf_sha1": "96d5295faf56", "answer_pdf_sha1": "2f6eb3654efb", "source_family": "moex-gov-tw", "moex": {"exam_code": "113040", "c": "306", "s": "1102", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學", "year": "113", "exam_name": "113年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 21, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "金融保險"}'::jsonb, NULL),
  ('disabled-7c4986e7-moex-00083', 'disabled-7c4986e7', 'disabled-7c4986e7-moex-113-e0b1f2ed', 'sub-disabled-7c4986e7-04', NULL, 'single_choice', '如果一家企業選擇使用攤銷後成本法來處理其公司債的發行成本，這些成 本將會如何進行會計處理？', '["從發行公司債的面額中直接扣除", "發生時認定為當期的費用", "延遲至債券到期時方認列為費用", "被視作發行公司債取得金額的減項，並在該債券的剩餘期間攤銷"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:58+00:00", "source_pdf_sha1": "96d5295faf56", "answer_pdf_sha1": "2f6eb3654efb", "source_family": "moex-gov-tw", "moex": {"exam_code": "113040", "c": "306", "s": "1102", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學", "year": "113", "exam_name": "113年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 22, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "金融保險"}'::jsonb, NULL),
  ('disabled-7c4986e7-moex-00084', 'disabled-7c4986e7', 'disabled-7c4986e7-moex-113-e0b1f2ed', 'sub-disabled-7c4986e7-04', NULL, 'single_choice', '百年企業於X2 年以每股$50 購回10,000 股流通在外的股票，並於同年度 以每股$40 再出售該10,000 股庫藏股票，在X2 年度中，百年企業沒有進 行其他與股東權益相關的交易。X2年初「資本公積－庫藏股票交易」的貸 方餘額為$200,000，試問再出售庫藏股票時，對於保留盈餘與資本公積將 產生何種影響？', '["保留盈餘增加，資本公積減少", "保留盈餘無影響，資本公積增加", "保留盈餘減少，資本公積增加", "保留盈餘無影響，資本公積減少"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:58+00:00", "source_pdf_sha1": "96d5295faf56", "answer_pdf_sha1": "2f6eb3654efb", "source_family": "moex-gov-tw", "moex": {"exam_code": "113040", "c": "306", "s": "1102", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學", "year": "113", "exam_name": "113年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 23, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "金融保險"}'::jsonb, NULL),
  ('disabled-7c4986e7-moex-00085', 'disabled-7c4986e7', 'disabled-7c4986e7-moex-113-e0b1f2ed', 'sub-disabled-7c4986e7-04', NULL, 'single_choice', '乙公司於 X3 年初平價發行$500,000 可轉換公司債，轉換價格為$25。X6 年12月1日為誘導轉換為普通股（每股面額$5），將轉換價格降為$20， 當時乙公司股價為$30。X6年無公司債進行轉換，則乙公司修改轉換價格 對X6年度綜合損益總額之影響為：（不考慮所得稅影響）', '["減少$75,000", "減少$150,000", "減少$225,000", "減少$300,000"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:58+00:00", "source_pdf_sha1": "96d5295faf56", "answer_pdf_sha1": "2f6eb3654efb", "source_family": "moex-gov-tw", "moex": {"exam_code": "113040", "c": "306", "s": "1102", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學", "year": "113", "exam_name": "113年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 24, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "金融保險"}'::jsonb, NULL)
